20→
21→class AssignRolesDto {
22→  @IsArray()
23→  @IsUUID('4', { each: true })
24→  roleIds: string[];
25→}
26→
27→@Controller('admin/users')
28→@UseGuards(RolesGuard)
29→@Roles('admin')
30→export class AdminController {
31→  constructor(
32→    private readonly authService: AuthService,
33→    private readonly lockoutService: LockoutService,
34→    @InjectRepository(UserRole)
35→    private readonly userRoleRepo: Repository<UserRole>,
36→  ) {}
37→
38→  @Post(':id/reset-password')
39→  async resetPassword(
40→    @Param('id') userId: string,
41→    @CurrentUser('id') adminId: string,
42→  ) {
43→    return this.authService.adminResetPassword(adminId, userId);
44→  }
45→
46→  @Post(':id/unlock')
47→  @HttpCode(HttpStatus.NO_CONTENT)
48→  async unlock(
49→    @Param('id') userId: string,
50→    @CurrentUser('id') adminId: string,
51→  ) {
52→    await this.lockoutService.unlock(userId, adminId);
53→  }
54→
55→  @Post(':id/roles')
56→  async assignRoles(
57→    @Param('id') userId: string,
58→    @Body() dto: AssignRolesDto,
59→    @CurrentUser('id') adminId: string,
60→  ) {
61→    // Remove existing roles and assign new ones
62→    await this.userRoleRepo.delete({ userId });
63→    const newRoles = dto.roleIds.map((roleId) =>
64→      this.userRoleRepo.create({
65→        userId,
66→        roleId,
67→        assignedBy: adminId,
68→      }),
69→    );
70→    await this.userRoleRepo.save(newRoles);
71→    return { userId, roleIds: dto.roleIds };
72→  }
73→
74→  @Delete(':id/roles/:roleId')
75→  @HttpCode(HttpStatus.NO_CONTENT)
76→  async removeRole(
77→    @Param('id') userId: string,
78→    @Param('roleId') roleId: string,
79→  ) {
80→    await this.userRoleRepo.delete({ userId, roleId });
81→  }
82→}
