  1→import { Injectable, NotFoundException } from '@nestjs/common';
  2→import { InjectRepository } from '@nestjs/typeorm';
  3→import { Repository } from 'typeorm';
  4→import { User } from './user.entity';
  5→import { EncryptionService } from '../encryption/encryption.service';
  6→
  7→@Injectable()
  8→export class UsersService {
  9→  constructor(
 10→    @InjectRepository(User)
 11→    private userRepo: Repository<User>,
 12→    private encryptionService: EncryptionService,
 13→  ) {}
 14→
 15→  async findById(id: string): Promise<User> {
 16→    const user = await this.userRepo.findOne({
 17→      where: { id },
 18→      relations: ['userRoles', 'userRoles.role'],
 19→    });
 20→    if (!user) throw new NotFoundException('User not found');
 21→    return this.decryptSensitiveFields(user);
 22→  }
 23→
 24→  private decryptSensitiveFields(user: User): User {
 25→    if (user.governmentId) {
 26→      try {
 27→        user.governmentId = this.encryptionService.decrypt(user.governmentId);
 28→      } catch {
 29→        // Field may not be encrypted yet (legacy data)
 30→      }
 31→    }
 32→    if (user.employeeId) {
 33→      try {
 34→        user.employeeId = this.encryptionService.decrypt(user.employeeId);
 35→      } catch {
 36→        // Field may not be encrypted yet (legacy data)
 37→      }
 38→    }
 39→    return user;
 40→  }
 41→
 42→  async findAll(query: {
 43→    page?: number;
 44→    pageSize?: number;
 45→    search?: string;
 46→    role?: string;
 47→    isActive?: boolean;
 48→  }) {
 49→    const page = query.page || 1;
 50→    const pageSize = Math.min(query.pageSize || 20, 100);
 51→
 52→    const qb = this.userRepo
 53→      .createQueryBuilder('u')
 54→      .leftJoinAndSelect('u.userRoles', 'ur')
 55→      .leftJoinAndSelect('ur.role', 'r');
 56→
 57→    if (query.search) {
 58→      qb.andWhere(
 59→        '(u.username ILIKE :search OR u.displayName ILIKE :search)',
 60→        { search: `%${query.search}%` },
 61→      );
 62→    }
 63→    if (query.role) {
 64→      qb.andWhere('r.name = :role', { role: query.role });
 65→    }
 66→    if (query.isActive !== undefined) {
 67→      qb.andWhere('u.isActive = :isActive', { isActive: query.isActive });
 68→    }
 69→
 70→    qb.orderBy('u.createdAt', 'DESC');
 71→    qb.skip((page - 1) * pageSize).take(pageSize);
 72→
 73→    const [items, total] = await qb.getManyAndCount();
 74→    return { items: items.map((u) => this.decryptSensitiveFields(u)), total, page, pageSize };
 75→  }
 76→
 77→  async updateProfile(
 78→    userId: string,
 79→    data: {
 80→      displayName?: string;
 81→      department?: string;
 82→      governmentId?: string;
 83→      employeeId?: string;
 84→    },
 85→  ): Promise<User> {
 86→    const user = await this.findById(userId);
 87→    if (data.displayName !== undefined) user.displayName = data.displayName;
 88→    if (data.department !== undefined) user.department = data.department || null;
 89→    if (data.governmentId !== undefined) {
 90→      user.governmentId = data.governmentId
 91→        ? this.encryptionService.encrypt(data.governmentId)
 92→        : null;
 93→    }
 94→    if (data.employeeId !== undefined) {
 95→      user.employeeId = data.employeeId
 96→        ? this.encryptionService.encrypt(data.employeeId)
 97→        : null;
 98→    }
 99→    const saved = await this.userRepo.save(user);
100→    return this.decryptSensitiveFields(saved);
101→  }
102→}
