153→  async cancelEnrollment(
154→    enrollmentId: string,
155→    userId: string,
156→    idempotencyKey: string,
157→    reason?: string,
158→    roles: string[] = [],
159→  ) {
160→    const idempCheck = await this.idempotencyService.check(
161→      idempotencyKey,
162→      'enrollments.cancel',
163→      userId,
164→    );
165→    if (idempCheck.isDuplicate) {
166→      return idempCheck.storedResponse!.body;
167→    }
168→
169→    return this.dataSource.transaction(async (manager) => {
170→      const enrollment = await manager
171→        .createQueryBuilder(Enrollment, 'e')
172→        .setLock('pessimistic_write')
173→        .where('e.id = :id', { id: enrollmentId })
174→        .getOne();
175→
176→      if (!enrollment) {
177→        throw new NotFoundException('Enrollment not found');
178→      }
179→
180→      if (!this.canAccessUserResource(enrollment.userId, userId, roles)) {
181→        throw new ForbiddenException('You can only cancel your own enrollments');
182→      }
183→
184→      if (enrollment.status === EnrollmentStatus.CANCELED) {
185→        throw new BadRequestException('Enrollment is already canceled');
186→      }
187→
188→      const previousStatus = enrollment.status;
189→      enrollment.status = EnrollmentStatus.CANCELED;
190→      enrollment.canceledAt = new Date();
191→      enrollment.cancelReason = reason || null;
192→      await manager.save(enrollment);
193→
194→      // Return seat if was confirmed
195→      if (previousStatus === EnrollmentStatus.CONFIRMED) {
196→        await manager
197→          .createQueryBuilder()
198→          .update(Offering)
199→          .set({ seatsAvailable: () => '"seatsAvailable" + 1' })
200→          .where('id = :id', { id: enrollment.offeringId })
201→          .execute();
202→      }
203→
204→      await manager.save(
205→        manager.create(EnrollmentStateTransition, {
206→          enrollmentId: enrollment.id,
207→          fromState: previousStatus,
208→          toState: 'CANCELED',
209→          actorId: userId,
210→          traceId: getTraceId(),
211→          reason: reason || 'Enrollment canceled',
212→        }),
213→      );
214→
215→      await this.auditService.recordEvent({
216→        action: 'enrollment.cancel',
217→        resourceType: 'enrollments',
218→        resourceId: enrollmentId,
219→        actorId: userId,
220→      });
221→
222→      const response = {
223→        id: enrollment.id,
224→        offeringId: enrollment.offeringId,
225→        status: enrollment.status,
226→        canceledAt: enrollment.canceledAt,
227→      };
228→
229→      await this.idempotencyService.store(
230→        idempotencyKey,
231→        'enrollments.cancel',
232→        userId,
233→        200,
234→        response,
235→      );
236→
237→      return response;
238→    });
239→  }
