241→  async approveEnrollment(
242→    enrollmentId: string,
243→    actorId: string,
244→    reason?: string,
245→  ) {
246→    return this.dataSource.transaction(async (manager) => {
247→      const enrollment = await manager
248→        .createQueryBuilder(Enrollment, 'e')
249→        .setLock('pessimistic_write')
250→        .where('e.id = :id', { id: enrollmentId })
251→        .getOne();
252→
253→      if (!enrollment) throw new NotFoundException('Enrollment not found');
254→      if (enrollment.status !== EnrollmentStatus.WAITLISTED) {
255→        throw new BadRequestException('Can only approve waitlisted enrollments');
256→      }
257→
258→      enrollment.status = EnrollmentStatus.APPROVED;
259→      enrollment.approvedAt = new Date();
260→      await manager.save(enrollment);
261→
262→      await manager.save(
263→        manager.create(EnrollmentStateTransition, {
264→          enrollmentId: enrollment.id,
265→          fromState: 'WAITLISTED',
266→          toState: 'APPROVED',
267→          actorId,
268→          traceId: getTraceId(),
269→          reason: reason || 'Enrollment approved',
270→        }),
271→      );
272→
273→      await this.auditService.recordEvent({
274→        action: 'enrollment.approve',
275→        resourceType: 'enrollments',
276→        resourceId: enrollmentId,
277→        actorId,
278→      });
