284→  async findAll(query: {
285→    page?: number;
286→    pageSize?: number;
287→    offeringId?: string;
288→    status?: string;
289→    userId?: string;
290→  }) {
291→    const page = query.page || 1;
292→    const pageSize = Math.min(query.pageSize || 20, 100);
293→
294→    const qb = this.enrollmentRepo.createQueryBuilder('e');
295→    if (query.offeringId) qb.andWhere('e.offeringId = :oid', { oid: query.offeringId });
296→    if (query.status) qb.andWhere('e.status = :status', { status: query.status });
297→    if (query.userId) qb.andWhere('e.userId = :uid', { uid: query.userId });
298→
299→    qb.orderBy('e.createdAt', 'DESC');
300→    qb.skip((page - 1) * pageSize).take(pageSize);
301→
302→    const [items, total] = await qb.getManyAndCount();
303→    return { items, total, page, pageSize };
304→  }
