306→  async findById(id: string): Promise<Enrollment & { transitions?: EnrollmentStateTransition[] }> {
307→    const enrollment = await this.enrollmentRepo.findOne({ where: { id } });
308→    if (!enrollment) throw new NotFoundException('Enrollment not found');
309→
310→    const transitions = await this.transitionRepo.find({
311→      where: { enrollmentId: id },
312→      order: { timestamp: 'ASC' },
313→    });
314→
315→    return { ...enrollment, transitions };
