  1→import {
  2→  Injectable,
  3→  BadRequestException,
  4→  HttpException,
  5→  HttpStatus,
  6→} from '@nestjs/common';
  7→import { AppConfigService } from '../config/config.service';
  8→import { AuditService } from '../audit/audit.service';
  9→import { readFileSync } from 'fs';
 10→import { v4 as uuidv4 } from 'uuid';
 11→
 12→const ALLOWED_EXTENSIONS: Record<string, string[]> = {
 13→  '.epub': ['application/epub+zip'],
 14→  '.pdf': ['application/pdf'],
 15→  '.txt': ['text/plain'],
 16→  '.mp4': ['video/mp4'],
 17→  '.mp3': ['audio/mpeg'],
 18→};
 19→
 20→const MAGIC_BYTES: Record<string, Buffer[]> = {
 21→  '.epub': [Buffer.from([0x50, 0x4b, 0x03, 0x04])], // ZIP (EPUB is ZIP-based)
 22→  '.pdf': [Buffer.from('%PDF', 'ascii')],
 23→  '.mp4': [], // ftyp box — checked by structure
 24→  '.mp3': [
 25→    Buffer.from([0xff, 0xfb]), // MPEG sync
 26→    Buffer.from([0xff, 0xf3]),
 27→    Buffer.from([0xff, 0xf2]),
 28→    Buffer.from('ID3', 'ascii'), // ID3 tag
 29→  ],
 30→};
 31→
 32→// PDF dangerous keywords
 33→const PDF_DANGEROUS_PATTERNS = [
 34→  '/JavaScript',
 35→  '/JS',
 36→  '/Launch',
 37→  '/EmbeddedFile',
 38→  '/OpenAction',
 39→  '/AA',
 40→];
 41→
 42→@Injectable()
 43→export class FileValidatorService {
 44→  constructor(
 45→    private config: AppConfigService,
 46→    private auditService: AuditService,
 47→  ) {}
 48→
 49→  sanitizeFilename(originalName: string): string {
 50→    let name = originalName;
 51→    // Strip path traversal
 52→    name = name.replace(/\.\.\//g, '').replace(/\.\.\\/g, '');
 53→    // Strip null bytes
 54→    name = name.replace(/\0/g, '');
 55→    // Strip control characters
 56→    name = name.replace(/[\x00-\x1f\x7f]/g, '');
 57→    // Replace spaces with underscores
 58→    name = name.replace(/\s+/g, '_');
 59→    // Keep only safe characters
 60→    name = name.replace(/[^a-zA-Z0-9._-]/g, '_');
 61→    // Truncate
 62→    if (name.length > 255) {
 63→      const ext = this.getExtension(name);
 64→      name = name.substring(0, 255 - ext.length) + ext;
 65→    }
 66→    if (!name) name = 'unnamed_file';
 67→    // Prefix with UUID to prevent collisions
 68→    const prefix = uuidv4().substring(0, 8);
 69→    return `${prefix}_${name}`;
 70→  }
 71→
 72→  getExtension(filename: string): string {
 73→    const lastDot = filename.lastIndexOf('.');
 74→    return lastDot >= 0 ? filename.substring(lastDot).toLowerCase() : '';
 75→  }
 76→
 77→  validateExtension(filename: string): string {
 78→    const ext = this.getExtension(filename);
 79→    if (!ALLOWED_EXTENSIONS[ext]) {
 80→      throw new HttpException(
 81→        `File type '${ext}' is not allowed. Allowed: ${Object.keys(ALLOWED_EXTENSIONS).join(', ')}`,
 82→        HttpStatus.UNSUPPORTED_MEDIA_TYPE,
 83→      );
 84→    }
 85→    return ext;
 86→  }
 87→
 88→  validateSize(size: number): void {
 89→    if (size > this.config.maxFileSizeBytes) {
 90→      throw new HttpException(
 91→        `File size ${size} exceeds maximum of ${this.config.maxFileSizeBytes} bytes (250 MB)`,
 92→        HttpStatus.PAYLOAD_TOO_LARGE,
 93→      );
 94→    }
 95→  }
 96→
 97→  validateMagicBytes(buffer: Buffer, extension: string): void {
 98→    const expectedMagic = MAGIC_BYTES[extension];
 99→    if (!expectedMagic || expectedMagic.length === 0) return;
100→
101→    const header = buffer.subarray(0, 8);
102→    const matches = expectedMagic.some((magic) =>
103→      header.subarray(0, magic.length).equals(magic),
104→    );
105→
106→    if (!matches) {
107→      throw new HttpException(
108→        'File content does not match declared file type',
109→        HttpStatus.UNSUPPORTED_MEDIA_TYPE,
110→      );
111→    }
112→  }
113→
114→  async validateStructure(
115→    filePath: string,
116→    extension: string,
117→    userId?: string,
118→  ): Promise<void> {
119→    try {
120→      if (extension === '.pdf') {
121→        await this.validatePdfStructure(filePath);
122→      } else if (extension === '.epub') {
123→        await this.validateEpubStructure(filePath);
124→      }
125→      // MP4/MP3/TXT: no structural validation beyond magic bytes
126→    } catch (err: any) {
127→      await this.auditService.recordEvent({
128→        action: 'file.structural_validation_failed',
129→        resourceType: 'files',
130→        actorId: userId,
131→        reason: err.message,
132→      });
133→      throw new HttpException(
134→        `File failed structural validation: ${err.message}`,
135→        HttpStatus.UNPROCESSABLE_ENTITY,
136→      );
137→    }
138→  }
139→
140→  private async validatePdfStructure(filePath: string): Promise<void> {
141→    const content = readFileSync(filePath, 'ascii');
142→    for (const pattern of PDF_DANGEROUS_PATTERNS) {
143→      if (content.includes(pattern)) {
144→        throw new Error(
145→          `PDF contains potentially dangerous element: ${pattern}`,
146→        );
147→      }
148→    }
149→  }
150→
151→  private async validateEpubStructure(filePath: string): Promise<void> {
152→    // EPUB is a ZIP file. Check for suspicious entries.
153→    // We read the first bytes to verify ZIP structure
154→    const buffer = readFileSync(filePath);
155→    if (buffer.length < 4) {
156→      throw new Error('EPUB file too small to be valid');
157→    }
158→    // Check ZIP magic
159→    if (buffer[0] !== 0x50 || buffer[1] !== 0x4b) {
160→      throw new Error('EPUB file is not a valid ZIP archive');
161→    }
162→    // Check for executable extensions in ZIP entries by scanning for common patterns
163→    const content = buffer.toString('ascii');
164→    const dangerousExts = ['.exe', '.bat', '.cmd', '.sh', '.ps1', '.vbs', '.js'];
165→    for (const ext of dangerousExts) {
166→      // Look for filenames ending in dangerous extensions within the ZIP directory
167→      const pattern = ext + '\x00'; // null-terminated in ZIP
168→      if (content.includes(pattern)) {
169→        throw new Error(`EPUB contains potentially dangerous file type: ${ext}`);
170→      }
171→    }
172→  }
173→}
