 1→import {
 2→  Controller,
 3→  Get,
 4→  Query,
 5→  Res,
 6→  NotFoundException,
 7→  ForbiddenException,
 8→  BadRequestException,
 9→} from '@nestjs/common';
10→import { Response } from 'express';
11→import { DownloadTokenService } from './download-token.service';
12→import { FilesService } from './files.service';
13→import { InjectRepository } from '@nestjs/typeorm';
14→import { Repository } from 'typeorm';
15→import { ContentAssetVersion } from '../content/content-asset-version.entity';
16→import { CurrentUser } from '../common/decorators/current-user.decorator';
17→
18→@Controller('files')
19→export class FilesController {
20→  constructor(
21→    private readonly downloadTokenService: DownloadTokenService,
22→    private readonly filesService: FilesService,
23→    @InjectRepository(ContentAssetVersion)
24→    private readonly versionRepo: Repository<ContentAssetVersion>,
25→  ) {}
26→
27→  @Get('download')
28→  async download(
29→    @Query('token') token: string,
30→    @CurrentUser('id') userId: string,
31→    @Res() res: Response,
32→  ) {
33→    if (!token) {
34→      throw new BadRequestException('Download token is required');
35→    }
36→    const payload = this.downloadTokenService.validateToken(token);
37→    if (payload.userId !== userId) {
38→      throw new ForbiddenException('Download token does not belong to this user');
39→    }
40→
41→    const version = await this.versionRepo.findOne({
42→      where: { id: payload.versionId, assetId: payload.assetId },
43→    });
44→    if (!version) {
45→      throw new NotFoundException('File version not found');
46→    }
47→
48→    const stream = this.filesService.getFileStream(version.filePath);
49→    res.setHeader('Content-Type', version.mimeType || 'application/octet-stream');
50→    res.setHeader('Content-Disposition', `attachment; filename="${version.filePath.split('/').pop()}"`);
51→    stream.pipe(res);
52→  }
53→}
