154→      if (data.effectiveFrom !== undefined) asset.effectiveFrom = data.effectiveFrom || null;
155→      if (data.effectiveTo !== undefined) asset.effectiveTo = data.effectiveTo || null;
156→      await manager.save(asset);
157→
158→      // Determine version bump
159→      const newVersion = this.bumpVersion(
