 18→
 19→class RegisterDto {
 20→  @IsString()
 21→  @MinLength(3)
 22→  @MaxLength(255)
 23→  @Matches(/^[a-zA-Z0-9_]+$/, { message: 'Username must be alphanumeric with underscores' })
 24→  username: string;
 25→
 26→  @IsString()
 27→  @MinLength(12)
 28→  password: string;
 29→
 30→  @IsString()
 31→  @MinLength(1)
 32→  @MaxLength(255)
 33→  displayName: string;
 34→
 35→  @IsString()
 36→  challengeId: string;
 37→
 38→  @IsString()
 39→  nonce: string;
 40→}
 41→
 42→class LoginDto {
 43→  @IsString()
 44→  username: string;
 45→
 46→  @IsString()
 47→  password: string;
 48→
 49→  @IsOptional()
 50→  @IsString()
 51→  challengeId?: string;
 52→
 53→  @IsOptional()
 54→  @IsString()
 55→  nonce?: string;
 56→}
 57→
 58→class ChangePasswordDto {
 59→  @IsString()
 60→  currentPassword: string;
 61→
 62→  @IsString()
 63→  @MinLength(12)
 64→  newPassword: string;
 65→}
 66→
 67→class ResetPasswordDto {
 68→  @IsString()
 69→  token: string;
 70→
 71→  @IsString()
 72→  @MinLength(12)
 73→  newPassword: string;
 74→
 75→  @IsString()
 76→  challengeId: string;
 77→
 78→  @IsString()
 79→  nonce: string;
 80→}
