10→  constructor(
11→    @InjectRepository(AuditEvent)
12→    private auditRepo: Repository<AuditEvent>,
13→  ) {}
14→
15→  async recordEvent(event: {
16→    traceId?: string;
17→    actorId?: string;
18→    action: string;
19→    resourceType: string;
20→    resourceId?: string;
21→    changes?: any;
22→    reason?: string;
23→    ipAddress?: string;
24→    metadata?: any;
25→  }): Promise<void> {
26→    const auditEvent = this.auditRepo.create({
27→      traceId: event.traceId || getTraceId(),
28→      actorId: event.actorId || null,
29→      action: event.action,
30→      resourceType: event.resourceType,
31→      resourceId: event.resourceId || null,
32→      changes: event.changes || null,
33→      reason: event.reason || null,
34→      ipAddress: event.ipAddress || null,
35→      metadata: event.metadata || null,
36→    });
37→    await this.auditRepo.save(auditEvent);
38→  }
39→
40→  async findAll(query: {
41→    page?: number;
42→    pageSize?: number;
43→    actorId?: string;
44→    resourceType?: string;
45→    resourceId?: string;
46→    action?: string;
47→    traceId?: string;
48→    from?: Date;
49→    to?: Date;
50→  }) {
51→    const page = query.page || 1;
52→    const pageSize = Math.min(query.pageSize || 20, 100);
53→
54→    const qb = this.auditRepo.createQueryBuilder('ae');
55→
56→    if (query.actorId) qb.andWhere('ae.actorId = :actorId', { actorId: query.actorId });
57→    if (query.resourceType) qb.andWhere('ae.resourceType = :resourceType', { resourceType: query.resourceType });
58→    if (query.resourceId) qb.andWhere('ae.resourceId = :resourceId', { resourceId: query.resourceId });
59→    if (query.action) qb.andWhere('ae.action = :action', { action: query.action });
60→    if (query.traceId) qb.andWhere('ae.traceId = :traceId', { traceId: query.traceId });
61→    if (query.from) qb.andWhere('ae.timestamp >= :from', { from: query.from });
62→    if (query.to) qb.andWhere('ae.timestamp <= :to', { to: query.to });
63→
64→    qb.orderBy('ae.timestamp', 'DESC');
65→    qb.skip((page - 1) * pageSize).take(pageSize);
66→
67→    const [items, total] = await qb.getManyAndCount();
68→    return { items, total, page, pageSize };
69→  }
70→
71→  async findById(id: string): Promise<AuditEvent | null> {
72→    return this.auditRepo.findOne({ where: { id } });
73→  }
74→}
