 31→
 32→  async confirmReservation(
 33→    reservationId: string,
 34→    userId: string,
 35→    idempotencyKey: string,
 36→  ) {
 37→    const idempCheck = await this.idempotencyService.check(
 38→      idempotencyKey,
 39→      'enrollments.confirm',
 40→      userId,
 41→    );
 42→    if (idempCheck.isDuplicate) {
 43→      return idempCheck.storedResponse!.body;
 44→    }
 45→
 46→    return this.dataSource.transaction(async (manager) => {
 47→      const reservation = await manager
 48→        .createQueryBuilder(Reservation, 'r')
 49→        .setLock('pessimistic_write')
 50→        .where('r.id = :id', { id: reservationId })
 51→        .getOne();
 52→
 53→      if (!reservation) {
 54→        throw new NotFoundException('Reservation not found');
 55→      }
 56→
 57→      if (reservation.userId !== userId) {
 58→        throw new BadRequestException('Reservation does not belong to you');
 59→      }
 60→
 61→      if (reservation.status !== ReservationStatus.HELD) {
 62→        throw new BadRequestException('Reservation is not in HELD status');
 63→      }
 64→
 65→      if (reservation.expiresAt < new Date()) {
 66→        throw new HttpException(
 67→          'Reservation has expired',
 68→          HttpStatus.GONE,
 69→        );
 70→      }
 71→
 72→      // Check for duplicate enrollment
 73→      const existingEnrollment = await manager
 74→        .createQueryBuilder(Enrollment, 'e')
 75→        .where('e.offeringId = :offeringId', {
 76→          offeringId: reservation.offeringId,
 77→        })
 78→        .andWhere('e.userId = :userId', { userId })
 79→        .andWhere("e.status != :canceled", {
 80→          canceled: EnrollmentStatus.CANCELED,
 81→        })
 82→        .getOne();
 83→
 84→      if (existingEnrollment) {
 85→        throw new ConflictException(
 86→          'You are already enrolled in this offering',
 87→        );
 88→      }
 89→
 90→      // Convert reservation
 91→      reservation.status = ReservationStatus.CONVERTED;
 92→      await manager.save(reservation);
 93→
 94→      // Create enrollment
 95→      const enrollment = manager.create(Enrollment, {
 96→        offeringId: reservation.offeringId,
 97→        userId,
 98→        reservationId,
 99→        status: EnrollmentStatus.CONFIRMED,
100→        confirmedAt: new Date(),
101→        idempotencyKey,
102→      });
103→      const saved = await manager.save(enrollment);
104→
105→      // Record transitions
106→      await manager.save(
107→        manager.create(EnrollmentStateTransition, {
108→          reservationId,
109→          fromState: 'HELD',
110→          toState: 'CONVERTED',
111→          actorId: userId,
112→          traceId: getTraceId(),
113→          reason: 'Reservation confirmed',
114→        }),
115→      );
116→      await manager.save(
117→        manager.create(EnrollmentStateTransition, {
118→          enrollmentId: saved.id,
119→          fromState: 'NONE',
120→          toState: 'CONFIRMED',
121→          actorId: userId,
122→          traceId: getTraceId(),
123→          reason: 'Enrollment confirmed from reservation',
124→        }),
125→      );
126→
127→      await this.auditService.recordEvent({
128→        action: 'enrollment.confirm',
129→        resourceType: 'enrollments',
130→        resourceId: saved.id,
131→        actorId: userId,
132→      });
133→
134→      const response = {
135→        id: saved.id,
136→        offeringId: saved.offeringId,
137→        status: saved.status,
138→        confirmedAt: saved.confirmedAt,
139→      };
140→
141→      await this.idempotencyService.store(
142→        idempotencyKey,
143→        'enrollments.confirm',
144→        userId,
145→        201,
146→        response,
147→      );
148→
149→      return response;
150→    });
151→  }
