155→    userId: string,
156→    idempotencyKey: string,
157→    reason?: string,
158→    roles: string[] = [],
159→  ) {
160→    const idempCheck = await this.idempotencyService.check(
161→      idempotencyKey,
162→      'enrollments.cancel',
163→      userId,
164→    );
165→    if (idempCheck.isDuplicate) {
166→      return idempCheck.storedResponse!.body;
167→    }
168→
169→    return this.dataSource.transaction(async (manager) => {
170→      const enrollment = await manager
171→        .createQueryBuilder(Enrollment, 'e')
172→        .setLock('pessimistic_write')
173→        .where('e.id = :id', { id: enrollmentId })
174→        .getOne();
175→
176→      if (!enrollment) {
177→        throw new NotFoundException('Enrollment not found');
178→      }
179→
180→      if (!this.canAccessUserResource(enrollment.userId, userId, roles)) {
181→        throw new ForbiddenException('You can only cancel your own enrollments');
182→      }
183→
184→      if (enrollment.status === EnrollmentStatus.CANCELED) {
185→        throw new BadRequestException('Enrollment is already canceled');
186→      }
187→
188→      const previousStatus = enrollment.status;
189→      enrollment.status = EnrollmentStatus.CANCELED;
