341→  /**
342→   * Promote next waitlisted user for an offering. Called by job.
343→   */
344→  async promoteNextWaitlisted(offeringId: string, traceId?: string): Promise<boolean> {
345→    return this.dataSource.transaction(async (manager) => {
346→      const offering = await manager
347→        .createQueryBuilder(Offering, 'o')
348→        .setLock('pessimistic_write')
349→        .where('o.id = :id', { id: offeringId })
350→        .getOne();
351→
352→      if (!offering || offering.seatsAvailable <= 0) return false;
353→
354→      const next = await manager
355→        .createQueryBuilder(Enrollment, 'e')
356→        .setLock('pessimistic_write')
357→        .where('e.offeringId = :oid AND e.status = :status', {
358→          oid: offeringId,
359→          status: EnrollmentStatus.WAITLISTED,
360→        })
361→        .orderBy('e.waitlistedAt', 'ASC')
362→        .getOne();
363→
364→      if (!next) return false;
365→
366→      const internalKey = `internal:enrollments.promote_waitlist:${next.id}`;
367→      const idemp = await this.idempotencyService.check(
368→        internalKey,
369→        'jobs.enrollments.promote_waitlist',
370→        '00000000-0000-0000-0000-000000000000',
371→      );
372→      if (idemp.isDuplicate) {
373→        return false;
374→      }
375→
376→      if (offering.requiresApproval) {
377→        next.status = EnrollmentStatus.APPROVED;
378→        next.approvedAt = new Date();
379→      } else {
380→        next.status = EnrollmentStatus.CONFIRMED;
381→        next.confirmedAt = new Date();
382→        // Decrement seat
383→        await manager
384→          .createQueryBuilder()
385→          .update(Offering)
386→          .set({ seatsAvailable: () => '"seatsAvailable" - 1' })
387→          .where('id = :id', { id: offeringId })
388→          .execute();
389→      }
390→      await manager.save(next);
391→
392→      await manager.save(
393→        manager.create(EnrollmentStateTransition, {
394→          enrollmentId: next.id,
395→          fromState: 'WAITLISTED',
396→          toState: next.status,
397→          actorId: '00000000-0000-0000-0000-000000000000',
398→          traceId: traceId || getTraceId(),
399→          reason: 'Auto-promoted from waitlist',
400→        }),
401→      );
402→
403→      await this.auditService.recordEvent({
404→        traceId: traceId || getTraceId(),
405→        action: 'enrollment.auto_promote',
406→        resourceType: 'enrollments',
407→        resourceId: next.id,
408→        actorId: '00000000-0000-0000-0000-000000000000',
409→        reason: 'Auto-promoted from waitlist',
410→      });
411→
412→      await this.idempotencyService.store(
413→        internalKey,
414→        'jobs.enrollments.promote_waitlist',
415→        '00000000-0000-0000-0000-000000000000',
416→        200,
417→        { enrollmentId: next.id, promoted: true },
418→      );
419→
420→      return true;
421→    });
422→  }
423→
424→  private canAccessUserResource(
425→    ownerUserId: string,
426→    actorUserId: string,
427→    roles: string[] = [],
428→  ): boolean {
429→    if (ownerUserId === actorUserId) {
430→      return true;
431→    }
432→    return roles.includes('admin') || roles.includes('enrollment_manager');
433→  }
434→}
