  1→import {
  2→  Injectable,
  3→  NotFoundException,
  4→  BadRequestException,
  5→  ForbiddenException,
  6→} from '@nestjs/common';
  7→import { InjectRepository } from '@nestjs/typeorm';
  8→import { Repository, DataSource } from 'typeorm';
  9→import { ContentAsset, AssetType } from './content-asset.entity';
 10→import { ContentAssetVersion } from './content-asset-version.entity';
 11→import { ContentLineage, LineageRelationship } from './content-lineage.entity';
 12→import { FilesService } from '../files/files.service';
 13→import { DownloadTokenService } from '../files/download-token.service';
 14→import { AppConfigService } from '../config/config.service';
 15→import { AuditService } from '../audit/audit.service';
 16→import { v4 as uuidv4 } from 'uuid';
 17→
 18→@Injectable()
 19→export class ContentService {
 20→  constructor(
 21→    @InjectRepository(ContentAsset)
 22→    private assetRepo: Repository<ContentAsset>,
 23→    @InjectRepository(ContentAssetVersion)
 24→    private versionRepo: Repository<ContentAssetVersion>,
 25→    @InjectRepository(ContentLineage)
 26→    private lineageRepo: Repository<ContentLineage>,
 27→    private filesService: FilesService,
 28→    private downloadTokenService: DownloadTokenService,
 29→    private config: AppConfigService,
 30→    private auditService: AuditService,
 31→    private dataSource: DataSource,
 32→  ) {}
 33→
 34→  async createAsset(
 35→    file: Express.Multer.File,
 36→    data: {
 37→      title: string;
 38→      assetType: AssetType;
 39→      author?: string;
 40→      publisher?: string;
 41→      effectiveFrom?: Date;
 42→      effectiveTo?: Date;
 43→      categoryIds?: string[];
 44→      tagIds?: string[];
 45→    },
 46→    userId: string,
 47→  ) {
 48→    const assetId = uuidv4();
 49→    const versionId = uuidv4();
 50→
 51→    const stored = await this.filesService.storeFile(
 52→      file,
 53→      assetId,
 54→      versionId,
 55→      userId,
 56→    );
 57→
 58→    return this.dataSource.transaction(async (manager) => {
 59→      const asset = manager.create(ContentAsset, {
 60→        id: assetId,
 61→        title: data.title,
 62→        assetType: data.assetType,
 63→        author: data.author || null,
 64→        publisher: data.publisher || null,
 65→        effectiveFrom: data.effectiveFrom || null,
 66→        effectiveTo: data.effectiveTo || null,
 67→        createdBy: userId,
 68→      });
 69→      await manager.save(asset);
 70→
 71→      const version = manager.create(ContentAssetVersion, {
 72→        id: versionId,
 73→        assetId: asset.id,
 74→        semanticVersion: '1.0.0',
 75→        filePath: stored.filePath,
 76→        fileHash: stored.fileHash,
 77→        fileSize: stored.fileSize,
 78→        mimeType: stored.mimeType,
 79→        isCurrent: true,
 80→        parseStatus: 'PENDING',
 81→        createdBy: userId,
 82→      });
 83→      await manager.save(version);
 84→
 85→      // Category/Tag associations handled via separate endpoints or here if IDs provided
 86→      if (data.categoryIds?.length) {
 87→        await manager
 88→          .createQueryBuilder()
 89→          .insert()
 90→          .into('asset_categories')
 91→          .values(
 92→            data.categoryIds.map((cid) => ({
 93→              assetId: asset.id,
 94→              categoryId: cid,
 95→            })),
 96→          )
 97→          .execute();
 98→      }
 99→
100→      if (data.tagIds?.length) {
101→        await manager
102→          .createQueryBuilder()
103→          .insert()
104→          .into('asset_tags')
105→          .values(
106→            data.tagIds.map((tid) => ({
107→              assetId: asset.id,
108→              tagId: tid,
109→            })),
110→          )
111→          .execute();
112→      }
113→
114→      await this.auditService.recordEvent({
115→        action: 'content.create',
116→        resourceType: 'content_assets',
117→        resourceId: asset.id,
118→        actorId: userId,
119→      });
120→
121→      return {
122→        ...asset,
123→        currentVersion: version,
124→      };
125→    });
126→  }
127→
128→  async updateAsset(
129→    assetId: string,
130→    file: Express.Multer.File | undefined,
131→    data: {
132→      title?: string;
133→      author?: string;
134→      publisher?: string;
135→      effectiveFrom?: Date;
136→      effectiveTo?: Date;
137→      bumpMajor?: boolean;
138→    },
139→    userId: string,
140→  ) {
141→    const asset = await this.assetRepo.findOne({ where: { id: assetId } });
142→    if (!asset) throw new NotFoundException('Content asset not found');
143→
144→    const currentVersion = await this.versionRepo.findOne({
145→      where: { assetId, isCurrent: true },
146→    });
147→    if (!currentVersion) throw new NotFoundException('No current version');
148→
149→    return this.dataSource.transaction(async (manager) => {
150→      // Update metadata
151→      if (data.title) asset.title = data.title;
152→      if (data.author !== undefined) asset.author = data.author || null;
153→      if (data.publisher !== undefined) asset.publisher = data.publisher || null;
154→      if (data.effectiveFrom !== undefined) asset.effectiveFrom = data.effectiveFrom || null;
155→      if (data.effectiveTo !== undefined) asset.effectiveTo = data.effectiveTo || null;
156→      await manager.save(asset);
157→
158→      // Determine version bump
159→      const newVersion = this.bumpVersion(
160→        currentVersion.semanticVersion,
161→        file ? 'minor' : 'patch',
162→        data.bumpMajor || false,
163→      );
164→
165→      let stored = {
166→        filePath: currentVersion.filePath,
167→        fileHash: currentVersion.fileHash,
168→        fileSize: currentVersion.fileSize,
169→        mimeType: currentVersion.mimeType,
170→      };
171→
172→      const versionId = uuidv4();
173→
174→      if (file) {
175→        stored = await this.filesService.storeFile(
176→          file,
177→          assetId,
178→          versionId,
179→          userId,
180→        );
181→      }
182→
183→      // Mark old version as not current
184→      currentVersion.isCurrent = false;
185→      await manager.save(currentVersion);
186→
187→      // Create new version
188→      const version = manager.create(ContentAssetVersion, {
189→        id: versionId,
190→        assetId,
191→        semanticVersion: newVersion,
192→        parentVersionId: currentVersion.id,
193→        filePath: stored.filePath,
194→        fileHash: stored.fileHash,
195→        fileSize: stored.fileSize,
196→        mimeType: stored.mimeType,
197→        isCurrent: true,
198→        parseStatus: file ? 'PENDING' : currentVersion.parseStatus,
199→        createdBy: userId,
200→      });
201→      await manager.save(version);
202→
203→      // Record lineage
204→      const lineage = manager.create(ContentLineage, {
205→        descendantVersionId: version.id,
206→        ancestorVersionId: currentVersion.id,
207→        relationshipType: LineageRelationship.DERIVED,
208→      });
209→      await manager.save(lineage);
210→
211→      await this.auditService.recordEvent({
212→        action: 'content.update',
213→        resourceType: 'content_assets',
214→        resourceId: assetId,
215→        actorId: userId,
216→        changes: { newVersion },
217→      });
218→
219→      return { ...asset, currentVersion: version };
220→    });
221→  }
222→
223→  async rollback(
224→    assetId: string,
225→    targetVersionId: string,
226→    userId: string,
227→  ) {
228→    const asset = await this.assetRepo.findOne({ where: { id: assetId } });
229→    if (!asset) throw new NotFoundException('Content asset not found');
230→
231→    const targetVersion = await this.versionRepo.findOne({
232→      where: { id: targetVersionId, assetId },
233→    });
234→    if (!targetVersion) {
235→      throw new BadRequestException('Target version not found for this asset');
236→    }
237→
238→    // Check 180-day window
239→    const cutoff = new Date();
240→    cutoff.setDate(cutoff.getDate() - this.config.rollbackWindowDays);
241→    if (targetVersion.createdAt < cutoff) {
242→      throw new BadRequestException(
243→        `Cannot rollback to version older than ${this.config.rollbackWindowDays} days`,
244→      );
245→    }
246→
247→    return this.dataSource.transaction(async (manager) => {
248→      const currentVersion = await manager.findOne(ContentAssetVersion, {
249→        where: { assetId, isCurrent: true },
250→      });
251→
252→      if (currentVersion) {
253→        currentVersion.isCurrent = false;
254→        await manager.save(currentVersion);
255→      }
256→
257→      const newVersion = manager.create(ContentAssetVersion, {
258→        id: uuidv4(),
259→        assetId,
260→        semanticVersion: this.bumpVersion(
261→          currentVersion?.semanticVersion || '1.0.0',
262→          'minor',
263→          false,
264→        ),
265→        parentVersionId: currentVersion?.id || null,
266→        sourceAssetId: targetVersion.sourceAssetId,
267→        filePath: targetVersion.filePath,
268→        fileHash: targetVersion.fileHash,
269→        fileSize: targetVersion.fileSize,
270→        mimeType: targetVersion.mimeType,
271→        isCurrent: true,
272→        parseStatus: targetVersion.parseStatus,
273→        createdBy: userId,
274→      });
275→      await manager.save(newVersion);
276→
277→      // Record rollback lineage
278→      const lineage = manager.create(ContentLineage, {
279→        descendantVersionId: newVersion.id,
280→        ancestorVersionId: targetVersion.id,
281→        relationshipType: LineageRelationship.ROLLBACK,
282→      });
283→      await manager.save(lineage);
284→
285→      await this.auditService.recordEvent({
286→        action: 'content.rollback',
287→        resourceType: 'content_assets',
288→        resourceId: assetId,
289→        actorId: userId,
290→        changes: {
291→          targetVersionId,
292→          newVersionId: newVersion.id,
293→        },
294→      });
295→
296→      return { ...asset, currentVersion: newVersion };
297→    });
298→  }
299→
300→  async findAll(query: {
301→    page?: number;
302→    pageSize?: number;
303→    search?: string;
304→    assetType?: string;
305→    categoryId?: string;
306→    tagId?: string;
307→    author?: string;
308→  }) {
309→    const page = query.page || 1;
310→    const pageSize = Math.min(query.pageSize || 20, 100);
311→
312→    const qb = this.assetRepo
313→      .createQueryBuilder('ca')
314→      .leftJoinAndSelect('ca.versions', 'v', 'v.isCurrent = true')
315→      .leftJoinAndSelect('ca.categories', 'cat')
316→      .leftJoinAndSelect('ca.tags', 'tag');
317→
318→    if (query.search) {
319→      qb.andWhere('(ca.title ILIKE :s OR ca.author ILIKE :s)', {
320→        s: `%${query.search}%`,
321→      });
322→    }
323→    if (query.assetType) {
324→      qb.andWhere('ca.assetType = :at', { at: query.assetType });
325→    }
326→    if (query.author) {
327→      qb.andWhere('ca.author ILIKE :author', { author: `%${query.author}%` });
328→    }
329→
330→    qb.orderBy('ca.updatedAt', 'DESC');
331→    qb.skip((page - 1) * pageSize).take(pageSize);
332→
333→    const [items, total] = await qb.getManyAndCount();
334→    return { items, total, page, pageSize };
335→  }
336→
337→  async findById(id: string) {
338→    const asset = await this.assetRepo.findOne({
339→      where: { id },
340→      relations: ['versions', 'categories', 'tags'],
341→    });
342→    if (!asset) throw new NotFoundException('Content asset not found');
343→    return asset;
344→  }
345→
346→  async getVersions(assetId: string) {
347→    return this.versionRepo.find({
348→      where: { assetId },
349→      order: { createdAt: 'DESC' },
350→    });
351→  }
352→
353→  async getVersion(assetId: string, versionId: string) {
354→    const version = await this.versionRepo.findOne({
355→      where: { id: versionId, assetId },
356→      relations: ['parsedDocuments'],
357→    });
358→    if (!version) throw new NotFoundException('Version not found');
359→    return version;
360→  }
361→
362→  async getDownloadToken(assetId: string, versionId: string, userId: string) {
363→    const version = await this.versionRepo.findOne({
364→      where: { id: versionId, assetId },
365→    });
366→    if (!version) throw new NotFoundException('Version not found');
367→    return this.downloadTokenService.generateToken(assetId, versionId, userId);
368→  }
369→
370→  async getLineage(assetId: string) {
371→    const versions = await this.versionRepo.find({
372→      where: { assetId },
373→      select: ['id'],
374→    });
375→    if (!versions.length) return [];
376→
377→    const versionIds = versions.map((v) => v.id);
378→    return this.lineageRepo
379→      .createQueryBuilder('cl')
380→      .where(
381→        'cl.descendantVersionId IN (:...vids) OR cl.ancestorVersionId IN (:...vids)',
382→        { vids: versionIds },
383→      )
384→      .orderBy('cl.createdAt', 'DESC')
385→      .getMany();
386→  }
387→
388→  async getDuplicateLinks(assetId: string) {
389→    const currentVersion = await this.versionRepo.findOne({
390→      where: { assetId, isCurrent: true },
391→    });
392→    if (!currentVersion) {
393→      throw new NotFoundException('No current version found for this asset');
394→    }
395→
396→    // Find all parsed documents for the current version
397→    const parsedDocs = await this.dataSource
398→      .createQueryBuilder()
399→      .select('pd.id')
400→      .from('parsed_documents', 'pd')
401→      .where('pd.versionId = :versionId', { versionId: currentVersion.id })
402→      .getRawMany();
403→
404→    if (!parsedDocs.length) {
405→      return [];
406→    }
407→
408→    const docIds = parsedDocs.map((d) => d.pd_id || d.id);
409→
410→    // Query duplicate_links where any of the parsed doc IDs appear as docA or docB
411→    return this.dataSource
412→      .createQueryBuilder()
413→      .select('dl')
414→      .from('duplicate_links', 'dl')
415→      .where('dl.docAId IN (:...docIds) OR dl.docBId IN (:...docIds)', { docIds })
416→      .getRawMany();
417→  }
418→
419→  private bumpVersion(
420→    current: string,
421→    level: 'patch' | 'minor' | 'major',
422→    forceMajor: boolean,
423→  ): string {
424→    const [major, minor, patch] = current.split('.').map(Number);
425→    if (forceMajor) return `${major + 1}.0.0`;
426→    if (level === 'major') return `${major + 1}.0.0`;
427→    if (level === 'minor') return `${major}.${minor + 1}.0`;
428→    return `${major}.${minor}.${patch + 1}`;
429→  }
430→}
