 22→const SYSTEM_ACTOR_ID = '00000000-0000-0000-0000-000000000000';
 23→
 24→@Injectable()
 25→export class ReservationsService {
 26→  constructor(
 27→    @InjectRepository(Reservation)
 28→    private reservationRepo: Repository<Reservation>,
 29→    @InjectRepository(Offering)
 30→    private offeringRepo: Repository<Offering>,
 31→    private idempotencyService: IdempotencyService,
 32→    private auditService: AuditService,
 33→    private config: AppConfigService,
 34→    private dataSource: DataSource,
 35→  ) {}
 36→
 37→  async createReservation(
 38→    offeringId: string,
 39→    userId: string,
 40→    idempotencyKey: string,
 41→  ) {
 42→    // Check idempotency
 43→    const idempCheck = await this.idempotencyService.check(
 44→      idempotencyKey,
 45→      'reservations.create',
 46→      userId,
 47→    );
 48→    if (idempCheck.isDuplicate) {
 49→      return idempCheck.storedResponse!.body;
 50→    }
 51→
 52→    return this.dataSource.transaction(async (manager) => {
 53→      // Lock the offering row for update
 54→      const offering = await manager
 55→        .createQueryBuilder(Offering, 'o')
 56→        .setLock('pessimistic_write')
 57→        .where('o.id = :id', { id: offeringId })
 58→        .getOne();
 59→
 60→      if (!offering) {
 61→        throw new NotFoundException('Offering not found');
 62→      }
 63→
 64→      if (!offering.isWindowOpen()) {
 65→        throw new BadRequestException('Enrollment window is not open');
 66→      }
 67→
 68→      // Check eligibility
 69→      await this.checkEligibility(offering, userId, manager);
 70→
 71→      // Check for existing active reservation or enrollment
 72→      const existingReservation = await manager.findOne(Reservation, {
 73→        where: {
 74→          offeringId,
 75→          userId,
 76→          status: ReservationStatus.HELD,
 77→        },
 78→      });
 79→      if (existingReservation) {
 80→        throw new ConflictException(
 81→          'You already have an active reservation for this offering',
 82→        );
 83→      }
 84→
 85→      const existingEnrollment = await manager
 86→        .createQueryBuilder(Enrollment, 'e')
 87→        .where('e.offeringId = :offeringId', { offeringId })
 88→        .andWhere('e.userId = :userId', { userId })
 89→        .andWhere("e.status != :canceled", { canceled: EnrollmentStatus.CANCELED })
 90→        .getOne();
 91→      if (existingEnrollment) {
 92→        throw new ConflictException(
 93→          'You are already enrolled in this offering',
 94→        );
 95→      }
 96→
 97→      const now = new Date();
 98→      const expiresAt = new Date(
 99→        now.getTime() + this.config.reservationHoldMinutes * 60 * 1000,
100→      );
101→
102→      if (offering.seatsAvailable > 0) {
103→        // Decrement seats atomically
104→        await manager
105→          .createQueryBuilder()
106→          .update(Offering)
107→          .set({ seatsAvailable: () => '"seatsAvailable" - 1' })
108→          .where('id = :id AND "seatsAvailable" > 0', { id: offeringId })
109→          .execute();
110→
111→        const reservation = manager.create(Reservation, {
112→          offeringId,
113→          userId,
114→          status: ReservationStatus.HELD,
115→          heldAt: now,
116→          expiresAt,
117→          idempotencyKey,
118→        });
119→        const saved = await manager.save(reservation);
120→
121→        // Record state transition
122→        await manager.save(
123→          manager.create(EnrollmentStateTransition, {
124→            reservationId: saved.id,
125→            fromState: 'NONE',
126→            toState: 'HELD',
127→            actorId: userId,
128→            traceId: getTraceId(),
129→            reason: 'Seat reserved',
130→          }),
131→        );
132→
133→        await this.auditService.recordEvent({
134→          action: 'reservation.create',
135→          resourceType: 'reservations',
136→          resourceId: saved.id,
137→          actorId: userId,
138→        });
139→
140→        const response = {
141→          id: saved.id,
142→          offeringId: saved.offeringId,
143→          status: saved.status,
144→          heldAt: saved.heldAt,
145→          expiresAt: saved.expiresAt,
146→        };
147→
148→        await this.idempotencyService.store(
149→          idempotencyKey,
150→          'reservations.create',
151→          userId,
152→          201,
153→          response,
154→        );
155→
156→        return response;
157→      } else if (offering.waitlistEnabled) {
158→        // Create waitlisted enrollment directly
159→        const enrollment = manager.create(Enrollment, {
160→          offeringId,
161→          userId,
162→          status: EnrollmentStatus.WAITLISTED,
163→          waitlistedAt: now,
164→          idempotencyKey,
165→        });
166→        const saved = await manager.save(enrollment);
167→
168→        await manager.save(
169→          manager.create(EnrollmentStateTransition, {
170→            enrollmentId: saved.id,
171→            fromState: 'NONE',
172→            toState: 'WAITLISTED',
173→            actorId: userId,
174→            traceId: getTraceId(),
175→            reason: 'No seats available, added to waitlist',
176→          }),
177→        );
178→
179→        await this.auditService.recordEvent({
180→          action: 'enrollment.waitlisted',
181→          resourceType: 'enrollments',
182→          resourceId: saved.id,
183→          actorId: userId,
184→        });
185→
186→        const response = {
187→          id: saved.id,
188→          offeringId: saved.offeringId,
189→          status: saved.status,
190→          waitlistedAt: saved.waitlistedAt,
191→        };
192→
193→        await this.idempotencyService.store(
194→          idempotencyKey,
195→          'reservations.create',
196→          userId,
197→          201,
198→          response,
199→        );
200→
201→        return response;
202→      } else {
203→        throw new HttpException(
204→          'No seats available and waitlist is not enabled',
205→          HttpStatus.UNPROCESSABLE_ENTITY,
206→        );
207→      }
208→    });
209→  }
