211→  async releaseReservation(
212→    reservationId: string,
213→    userId: string,
214→    idempotencyKey: string,
215→    roles: string[] = [],
216→  ): Promise<void> {
217→    const idempCheck = await this.idempotencyService.check(
218→      idempotencyKey,
219→      'reservations.release',
220→      userId,
221→    );
222→    if (idempCheck.isDuplicate) return;
223→
224→    await this.dataSource.transaction(async (manager) => {
225→      const reservation = await manager.findOne(Reservation, {
226→        where: { id: reservationId },
227→      });
228→      if (!reservation) throw new NotFoundException('Reservation not found');
229→      if (!this.canAccessUserResource(reservation.userId, userId, roles)) {
230→        throw new ForbiddenException('You can only release your own reservations');
231→      }
232→      if (reservation.status !== ReservationStatus.HELD) {
233→        throw new BadRequestException('Reservation is not in HELD status');
234→      }
235→
236→      reservation.status = ReservationStatus.RELEASED;
237→      reservation.releasedAt = new Date();
238→      await manager.save(reservation);
239→
240→      // Return seat
241→      await manager
242→        .createQueryBuilder()
243→        .update(Offering)
244→        .set({ seatsAvailable: () => '"seatsAvailable" + 1' })
245→        .where('id = :id', { id: reservation.offeringId })
246→        .execute();
247→
248→      await manager.save(
249→        manager.create(EnrollmentStateTransition, {
250→          reservationId: reservation.id,
251→          fromState: 'HELD',
252→          toState: 'RELEASED',
253→          actorId: userId,
254→          traceId: getTraceId(),
255→          reason: 'Manual release',
256→        }),
257→      );
258→
259→      await this.auditService.recordEvent({
260→        action: 'reservation.release',
261→        resourceType: 'reservations',
262→        resourceId: reservationId,
263→        actorId: userId,
264→      });
265→    });
266→
267→    await this.idempotencyService.store(
268→      idempotencyKey,
269→      'reservations.release',
270→      userId,
271→      204,
272→      null,
273→    );
274→  }
