304→  private async checkEligibility(
305→    offering: Offering,
306→    userId: string,
307→    manager: any,
308→  ): Promise<void> {
309→    const flags = offering.eligibilityFlags;
310→    if (!flags || Object.keys(flags).length === 0) return;
311→
312→    const user = await manager.findOne(User, { where: { id: userId } });
313→    if (!user) throw new BadRequestException('User not found');
314→
315→    if (flags.employeeOnly && !user.employeeId) {
316→      throw new BadRequestException(
317→        'This offering is restricted to employees only',
318→      );
319→    }
320→
321→    if (flags.departments && Array.isArray(flags.departments) && flags.departments.length > 0) {
322→      const userDept = flags.userDepartmentField
323→        ? (user as any)[flags.userDepartmentField]
324→        : user.department;
325→      if (!userDept || !flags.departments.includes(userDept)) {
326→        throw new BadRequestException(
327→          `This offering is restricted to the following departments: ${flags.departments.join(', ')}`,
328→        );
329→      }
330→    }
331→  }
