333→  /**
334→   * Auto-release expired reservations. Called by scheduled job.
335→   */
336→  async releaseExpiredReservations(traceId?: string): Promise<number> {
337→    const now = new Date();
338→
339→    // Use FOR UPDATE SKIP LOCKED to prevent double-processing
340→    const expired = await this.dataSource
341→      .createQueryBuilder(Reservation, 'r')
342→      .setLock('pessimistic_write_or_fail')
343→      .where('r.status = :status', { status: ReservationStatus.HELD })
344→      .andWhere('r.expiresAt < :now', { now })
345→      .getMany()
346→      .catch(() => [] as Reservation[]); // SKIP LOCKED not directly available, fallback
347→
348→    let released = 0;
349→    for (const reservation of expired) {
350→      const internalKey = `internal:reservations.auto_release:${reservation.id}`;
351→      const idemp = await this.idempotencyService.check(
352→        internalKey,
353→        'jobs.reservations.auto_release',
354→        SYSTEM_ACTOR_ID,
355→      );
356→      if (idemp.isDuplicate) {
357→        continue;
358→      }
359→
360→      try {
361→        await this.dataSource.transaction(async (manager) => {
362→          // Re-check status inside transaction
363→          const current = await manager
364→            .createQueryBuilder(Reservation, 'r')
365→            .setLock('pessimistic_write')
366→            .where('r.id = :id AND r.status = :status', {
367→              id: reservation.id,
368→              status: ReservationStatus.HELD,
369→            })
370→            .getOne();
371→
372→          if (!current) return;
373→
374→          current.status = ReservationStatus.RELEASED;
375→          current.releasedAt = now;
376→          await manager.save(current);
377→
378→          await manager
379→            .createQueryBuilder()
380→            .update(Offering)
381→            .set({ seatsAvailable: () => '"seatsAvailable" + 1' })
382→            .where('id = :id', { id: current.offeringId })
383→            .execute();
384→
385→          await manager.save(
386→            manager.create(EnrollmentStateTransition, {
387→              reservationId: current.id,
388→              fromState: 'HELD',
389→              toState: 'RELEASED',
390→              actorId: SYSTEM_ACTOR_ID,
391→              traceId: traceId || getTraceId(),
392→              reason: 'Auto-release: hold expired',
393→            }),
394→          );
395→
396→          await this.auditService.recordEvent({
397→            traceId: traceId || getTraceId(),
398→            action: 'reservation.auto_release',
399→            resourceType: 'reservations',
400→            resourceId: current.id,
401→            reason: 'Hold expired',
402→            actorId: SYSTEM_ACTOR_ID,
403→          });
404→
405→          await this.idempotencyService.store(
406→            internalKey,
407→            'jobs.reservations.auto_release',
408→            SYSTEM_ACTOR_ID,
409→            200,
410→            { reservationId: current.id, released: true },
411→          );
412→
413→          released++;
414→        });
415→      } catch {
416→        // Individual failures don't block others
417→      }
418→    }
419→
420→    return released;
421→  }
422→
423→  private canAccessUserResource(
424→    ownerUserId: string,
425→    actorUserId: string,
426→    roles: string[] = [],
427→  ): boolean {
428→    if (ownerUserId === actorUserId) {
429→      return true;
430→    }
431→    return roles.includes('admin') || roles.includes('enrollment_manager');
432→  }
433→}
