      'mp41', 'mp42', 'M4V ', 'M4A ', 'avc1', 'dash', 'msdh', 'msix'];
    if (!knownBrands.some((b) => brand.startsWith(b.trim()))) {
      throw new Error(`MP4 file has unrecognized brand: ${brand}`);
