    const buffer = readFileSync(filePath);
    if (buffer.length === 0) {
      throw new Error('Text file is empty');
    }
    // Verify no null bytes in the entire file
    if (buffer.includes(0x00)) {
      throw new Error('Text file contains null bytes — likely binary content');
    }
  }

