 1→import { Module } from '@nestjs/common';
 2→import { TypeOrmModule } from '@nestjs/typeorm';
 3→import { ParsedDocument } from './parsed-document.entity';
 4→import { ParsingService } from './parsing.service';
 5→
 6→@Module({
 7→  imports: [TypeOrmModule.forFeature([ParsedDocument])],
