 1→import { Injectable, Logger } from '@nestjs/common';
 2→import { Cron } from '@nestjs/schedule';
 3→import { InjectRepository } from '@nestjs/typeorm';
 4→import { Repository } from 'typeorm';
 5→import { ContentAssetVersion } from '../content/content-asset-version.entity';
 6→import { ParsingService } from '../parsed-documents/parsing.service';
 7→import { DuplicateDetectionService } from '../duplicate-detection/duplicate-detection.service';
 8→import { FilesService } from '../files/files.service';
 9→import { AuditService } from '../audit/audit.service';
10→
11→const MAX_RETRIES = 3;
12→
13→@Injectable()
14→export class ContentParsingJob {
15→  private readonly logger = new Logger(ContentParsingJob.name);
16→
17→  constructor(
18→    @InjectRepository(ContentAssetVersion)
19→    private versionRepo: Repository<ContentAssetVersion>,
20→    private parsingService: ParsingService,
21→    private duplicateDetection: DuplicateDetectionService,
22→    private filesService: FilesService,
23→    private auditService: AuditService,
24→  ) {}
25→
26→  @Cron('*/5 * * * *') // Every 5 minutes
27→  async parseUnprocessedContent(): Promise<void> {
28→    const pending = await this.versionRepo.find({
29→      where: { parseStatus: 'PENDING' },
30→    });
31→
32→    for (const version of pending) {
33→      // Atomically claim the version by setting status to PROCESSING
34→      const claimed = await this.versionRepo
35→        .createQueryBuilder()
36→        .update()
37→        .set({ parseStatus: 'PROCESSING' })
38→        .where('id = :id AND "parseStatus" = :status', {
39→          id: version.id,
40→          status: 'PENDING',
41→        })
42→        .execute();
43→
44→      if (!claimed.affected || claimed.affected === 0) {
45→        continue; // Another job instance already claimed this version
46→      }
47→
48→      try {
49→        this.logger.log(`Parsing version ${version.id}`);
50→
51→        const buffer = this.filesService.getFileBuffer(version.filePath);
52→        const docs = await this.parsingService.parseAndStore(
53→          version.id,
54→          buffer,
55→          version.mimeType,
56→        );
57→
58→        version.parseStatus = 'COMPLETED';
59→        await this.versionRepo.save(version);
60→
61→        // Trigger duplicate detection for each parsed document
62→        for (const doc of docs) {
63→          try {
64→            await this.duplicateDetection.detectExactDuplicates(doc.id);
65→            await this.duplicateDetection.detectNearDuplicates(doc.id);
66→          } catch (err) {
67→            this.logger.warn(
68→              `Duplicate detection failed for doc ${doc.id}: ${err}`,
69→            );
70→          }
71→        }
72→
73→        this.logger.log(
74→          `Parsed version ${version.id}: ${docs.length} documents`,
75→        );
76→      } catch (err) {
77→        version.parseRetries++;
78→        if (version.parseRetries >= MAX_RETRIES) {
79→          version.parseStatus = 'PARSE_ERROR';
80→          await this.auditService.recordEvent({
81→            action: 'content.parse_error',
82→            resourceType: 'content_asset_versions',
83→            resourceId: version.id,
84→            reason: `Parse failed after ${MAX_RETRIES} retries: ${err}`,
85→          });
86→        } else {
87→          version.parseStatus = 'PENDING'; // Reset to PENDING for retry
88→        }
89→        await this.versionRepo.save(version);
90→        this.logger.error(
91→          `Parse failed for version ${version.id} (retry ${version.parseRetries}): ${err}`,
92→        );
93→      }
94→    }
95→  }
96→}
