 1→import { ParsingService } from '../../src/parsed-documents/parsing.service';
 2→
 3→describe('ParsingService', () => {
 4→  let service: ParsingService;
 5→  let mockParsedDocRepo: any;
 6→
 7→  beforeEach(() => {
 8→    mockParsedDocRepo = {
 9→      create: jest.fn((data) => data),
10→      save: jest.fn((data) => Promise.resolve({ id: 'doc-' + Math.random(), ...data })),
11→      find: jest.fn().mockResolvedValue([]),
12→    };
13→    service = new ParsingService(mockParsedDocRepo);
14→  });
15→
16→  describe('normalizeText', () => {
17→    it('should lowercase text', () => {
18→      expect(service.normalizeText('Hello WORLD')).toBe('hello world');
19→    });
20→
21→    it('should collapse whitespace', () => {
22→      expect(service.normalizeText('hello   world')).toBe('hello world');
23→    });
24→
25→    it('should remove punctuation', () => {
26→      expect(service.normalizeText('hello, world!')).toBe('hello world');
27→    });
28→
29→    it('should trim whitespace', () => {
30→      expect(service.normalizeText('  hello world  ')).toBe('hello world');
31→    });
32→
33→    it('should handle empty string', () => {
34→      expect(service.normalizeText('')).toBe('');
35→    });
36→  });
37→
38→  describe('computeContentHash', () => {
39→    it('should produce consistent hash for same normalized text', () => {
40→      const hash1 = service.computeContentHash('Hello World');
41→      const hash2 = service.computeContentHash('hello world');
42→      expect(hash1).toBe(hash2);
43→    });
44→
45→    it('should produce different hashes for different text', () => {
46→      const hash1 = service.computeContentHash('Hello World');
47→      const hash2 = service.computeContentHash('Goodbye World');
48→      expect(hash1).not.toBe(hash2);
49→    });
50→
51→    it('should produce 64-character hex hash (SHA-256)', () => {
52→      const hash = service.computeContentHash('test');
53→      expect(hash).toHaveLength(64);
54→      expect(hash).toMatch(/^[0-9a-f]+$/);
55→    });
56→  });
57→
58→  describe('parseAndStore - Plain text', () => {
59→    it('should split text into sections on double newlines', async () => {
60→      const buffer = Buffer.from('Section one.\n\nSection two.\n\nSection three.');
61→      const docs = await service.parseAndStore('v1', buffer, 'text/plain');
62→      expect(docs).toHaveLength(3);
63→      expect(mockParsedDocRepo.save).toHaveBeenCalledTimes(3);
64→    });
65→
66→    it('should handle single section (no double newlines)', async () => {
67→      const buffer = Buffer.from('Just one section here.');
68→      const docs = await service.parseAndStore('v1', buffer, 'text/plain');
69→      expect(docs).toHaveLength(1);
70→    });
71→
72→    it('should compute content hash for each section', async () => {
73→      const buffer = Buffer.from('Section one.\n\nSection two.');
74→      await service.parseAndStore('v1', buffer, 'text/plain');
75→      const savedDocs = mockParsedDocRepo.save.mock.calls;
76→      for (const [doc] of savedDocs) {
77→        expect(doc.contentHash).toBeDefined();
78→        expect(doc.contentHash).toHaveLength(64);
79→      }
80→    });
81→  });
82→
83→  describe('parseAndStore - Non-text formats', () => {
84→    it('should return empty array for MP4', async () => {
85→      const buffer = Buffer.alloc(100);
86→      const docs = await service.parseAndStore('v1', buffer, 'video/mp4');
87→      expect(docs).toHaveLength(0);
88→    });
89→
90→    it('should return empty array for MP3', async () => {
91→      const buffer = Buffer.alloc(100);
92→      const docs = await service.parseAndStore('v1', buffer, 'audio/mpeg');
93→      expect(docs).toHaveLength(0);
94→    });
95→  });
96→});
